def _compute_padding_length(
    input_length, kernel_length, stride, dilation_rate=1
):
    """Compute padding length along one dimension."""
    if (input_length - 1) % stride == 0:
        total_padding_length = dilation_rate * (kernel_length - 1)
    else:
